import{_ as a,o as e,c as d,a2 as s}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"CEO 现金流驾驶舱 V3 计算规则与 CFO 确认表","description":"","frontmatter":{},"headers":[],"relativePath":"V3_计算规则与CFO确认表.md","filePath":"V3_计算规则与CFO确认表.md","lastUpdated":1783323851000}'),n={name:"V3_计算规则与CFO确认表.md"};function i(l,t,r,p,h,o){return e(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="ceo-现金流驾驶舱-v3-计算规则与-cfo-确认表" tabindex="-1">CEO 现金流驾驶舱 V3 计算规则与 CFO 确认表 <a class="header-anchor" href="#ceo-现金流驾驶舱-v3-计算规则与-cfo-确认表" aria-label="Permalink to &quot;CEO 现金流驾驶舱 V3 计算规则与 CFO 确认表&quot;">​</a></h1><p>文档版本：V0.1<br> 规则版本：<code>cashflow-rules-v0.1</code><br> 状态：全部为验证口径，待 CFO 确认</p><h2 id="_1-统一计算参数" tabindex="-1">1. 统一计算参数 <a class="header-anchor" href="#_1-统一计算参数" aria-label="Permalink to &quot;1. 统一计算参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>V3 默认值</th><th>用途</th><th>CFO 确认</th></tr></thead><tbody><tr><td>base_currency</td><td>CNY</td><td>统一金额币种</td><td>待确认</td></tr><tr><td>period_type</td><td>calendar_month</td><td>“本月”的范围</td><td>待确认</td></tr><tr><td>warning_overdue_days</td><td>1</td><td>黄灯最低逾期天数</td><td>待确认</td></tr><tr><td>red_overdue_days</td><td>30</td><td>红灯最低逾期天数</td><td>待确认</td></tr><tr><td>red_amount_threshold</td><td>1000000</td><td>大额应收阈值（元）</td><td>待确认</td></tr><tr><td>cash_safety_threshold</td><td>0</td><td>现金安全底线（元）</td><td>待确认</td></tr><tr><td>expected_date_strategy</td><td>expected_or_agreed</td><td>预计回款日期选择</td><td>待确认</td></tr><tr><td>task_as_of_time</td><td>08:30</td><td>今日任务生成时间</td><td>待确认</td></tr></tbody></table><p>所有参数集中配置并携带规则版本，禁止散落在页面组件中。</p><h2 id="_2-基础派生值" tabindex="-1">2. 基础派生值 <a class="header-anchor" href="#_2-基础派生值" aria-label="Permalink to &quot;2. 基础派生值&quot;">​</a></h2><h3 id="_2-1-应收累计回款" tabindex="-1">2.1 应收累计回款 <a class="header-anchor" href="#_2-1-应收累计回款" aria-label="Permalink to &quot;2.1 应收累计回款&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>累计回款 = Σ 有效实际回款金额（按应收编号关联）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-2-应收未回金额" tabindex="-1">2.2 应收未回金额 <a class="header-anchor" href="#_2-2-应收未回金额" aria-label="Permalink to &quot;2.2 应收未回金额&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>未回金额 = max(应收金额 - 累计回款, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-3-逾期天数" tabindex="-1">2.3 逾期天数 <a class="header-anchor" href="#_2-3-逾期天数" aria-label="Permalink to &quot;2.3 逾期天数&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果未回金额 = 0：逾期天数 = 0</span></span>
<span class="line"><span>如果统计日期 &lt;= 约定到账日期：逾期天数 = 0</span></span>
<span class="line"><span>否则：逾期天数 = 统计日期 - 约定到账日期</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>部分回款后仍有余额时，按剩余未回金额继续计算逾期，待 CFO 确认。</p><h2 id="_3-驾驶舱指标" tabindex="-1">3. 驾驶舱指标 <a class="header-anchor" href="#_3-驾驶舱指标" aria-label="Permalink to &quot;3. 驾驶舱指标&quot;">​</a></h2><h3 id="_3-1-当前可用现金" tabindex="-1">3.1 当前可用现金 <a class="header-anchor" href="#_3-1-当前可用现金" aria-label="Permalink to &quot;3.1 当前可用现金&quot;">​</a></h3><p>V3 默认取每个账户不晚于统计日期的最新一条余额快照：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前可用现金 = Σ 各账户最新可用余额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>受限金额是否需要再扣减，取决于财务提供的“可用余额”定义。</p><h3 id="_3-2-本月预计回款" tabindex="-1">3.2 本月预计回款 <a class="header-anchor" href="#_3-2-本月预计回款" aria-label="Permalink to &quot;3.2 本月预计回款&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有效预计日期 = 若预计到账日期存在则取预计到账日期，否则取约定到账日期</span></span>
<span class="line"><span>本月预计回款 = Σ 有效预计日期落在本月且未取消的应收未回金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>争议点：已逾期但仍未到账的应收是否继续计入本月预计回款。</p><h3 id="_3-3-本月实际回款" tabindex="-1">3.3 本月实际回款 <a class="header-anchor" href="#_3-3-本月实际回款" aria-label="Permalink to &quot;3.3 本月实际回款&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本月实际回款 = Σ 回款日期落在本月的有效回款金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-4-本月计划支出" tabindex="-1">3.4 本月计划支出 <a class="header-anchor" href="#_3-4-本月计划支出" aria-label="Permalink to &quot;3.4 本月计划支出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本月计划支出 = Σ 计划日期落在本月、状态属于 planned/pending/approved 的计划金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>是否排除可延后支出、是否只统计已审批支出，待 CFO 确认。</p><h3 id="_3-5-本月现金流缺口" tabindex="-1">3.5 本月现金流缺口 <a class="header-anchor" href="#_3-5-本月现金流缺口" aria-label="Permalink to &quot;3.5 本月现金流缺口&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>期末预测现金 = 当前可用现金 + 本月剩余预计回款 - 本月剩余计划支出</span></span>
<span class="line"><span>本月现金流缺口 = max(-期末预测现金, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>“剩余”默认指统计日期至月末，避免将本月已发生回款和支出重复计算。若只能获得整月计划，则需明确计划金额中是否包含已发生部分。</p><h3 id="_3-6-逾期回款金额" tabindex="-1">3.6 逾期回款金额 <a class="header-anchor" href="#_3-6-逾期回款金额" aria-label="Permalink to &quot;3.6 逾期回款金额&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逾期回款金额 = Σ（约定到账日 &lt; 统计日期且未回金额 &gt; 0）的未回金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-7-今日待处理事项" tabindex="-1">3.7 今日待处理事项 <a class="header-anchor" href="#_3-7-今日待处理事项" aria-label="Permalink to &quot;3.7 今日待处理事项&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>今日待处理 = 未关闭且 due_date &lt;= 统计日期的任务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>任务由确定性规则生成，不由大模型自行创建经营事实。</p><h2 id="_4-四张决策卡规则" tabindex="-1">4. 四张决策卡规则 <a class="header-anchor" href="#_4-四张决策卡规则" aria-label="Permalink to &quot;4. 四张决策卡规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>卡片</th><th>V3 判断</th><th>依赖数据</th><th>待确认</th></tr></thead><tbody><tr><td>钱够不够</td><td>缺口 &gt; 0 为红；期末预测现金低于安全阈值为黄；否则绿</td><td>余额、预计回款、计划支出</td><td>安全阈值、预计回款可信折扣</td></tr><tr><td>钱该进没进</td><td>存在逾期未回为黄；达到红灯天数或大额阈值为红</td><td>应收、实际回款</td><td>风险天数和金额阈值</td></tr><tr><td>钱能不能花</td><td>拟支出后缺口 &gt; 0 为红；低于安全阈值为黄；否则绿</td><td>可用现金、预计回款、计划支出、拟支出</td><td>是否区分刚性支出及预算</td></tr><tr><td>谁在处理</td><td>风险事项有负责人且有未关闭任务；无负责人或超期未处理升级</td><td>责任人、任务、跟进记录</td><td>升级时限、老板介入条件</td></tr></tbody></table><h2 id="_5-回款风险等级-v0-1" tabindex="-1">5. 回款风险等级 V0.1 <a class="header-anchor" href="#_5-回款风险等级-v0-1" aria-label="Permalink to &quot;5. 回款风险等级 V0.1&quot;">​</a></h2><p>按最高风险命中：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>退出候选：未回金额 = 0</span></span>
<span class="line"><span>绿：未回金额 &gt; 0，且距离到期超过 2 天</span></span>
<span class="line"><span>黄：距离到期 0-2 天，或逾期 1-29 天且未触发红灯金额条件</span></span>
<span class="line"><span>红：逾期 &gt;= 30 天，或逾期且未回金额 &gt;= 1,000,000 元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>风险规则只作真实样本验证，不作为正式经营结论。</p><h2 id="_6-任务生成-v0-1" tabindex="-1">6. 任务生成 V0.1 <a class="header-anchor" href="#_6-任务生成-v0-1" aria-label="Permalink to &quot;6. 任务生成 V0.1&quot;">​</a></h2><table tabindex="0"><thead><tr><th>触发条件</th><th>任务类型</th><th>默认责任人</th><th>老板介入</th></tr></thead><tbody><tr><td>本月现金流缺口 &gt; 0</td><td>cash_gap</td><td>财务负责人/CFO</td><td>不单独生成拍板事件，作为回款/付款事件证据</td></tr><tr><td>应收逾期且未回金额 &gt; 0</td><td>collection_overdue</td><td>应收责任人</td><td>红灯时是</td></tr><tr><td>计划支出导致现金缺口</td><td>expense_review</td><td>支出责任人/财务</td><td>已审批刚性支出导致缺口时是</td></tr><tr><td>应收或支出缺少责任人</td><td>owner_missing</td><td>数据管理员</td><td>超过 1 天未补全时是</td></tr></tbody></table><p>同一来源、任务类型和处理日不得重复生成未关闭任务。</p><h2 id="_7-计算结果必须返回的审计信息" tabindex="-1">7. 计算结果必须返回的审计信息 <a class="header-anchor" href="#_7-计算结果必须返回的审计信息" aria-label="Permalink to &quot;7. 计算结果必须返回的审计信息&quot;">​</a></h2><p>每个指标接口除数值外还应返回：</p><ul><li><code>asOfDate</code>：计算基准日；</li><li><code>periodStart</code> / <code>periodEnd</code>：统计范围；</li><li><code>batchId</code>：数据批次；</li><li><code>ruleVersion</code>：规则版本；</li><li><code>reviewStatus</code>：待 CFO 复核/已复核；</li><li><code>sourceCount</code>：参与计算的记录数；</li><li><code>formulaCode</code>：稳定公式编码；</li><li><code>warnings</code>：数据缺失或口径提示。</li></ul><h2 id="_8-cfo-核对方式" tabindex="-1">8. CFO 核对方式 <a class="header-anchor" href="#_8-cfo-核对方式" aria-label="Permalink to &quot;8. CFO 核对方式&quot;">​</a></h2><p>每个指标按以下结果记录核对：</p><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:right;">系统结果</th><th style="text-align:right;">财务手算结果</th><th style="text-align:right;">差异</th><th>结论</th><th>调整说明</th></tr></thead><tbody><tr><td>当前可用现金</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr><tr><td>本月预计回款</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr><tr><td>本月实际回款</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr><tr><td>本月计划支出</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr><tr><td>本月现金流缺口</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr><tr><td>逾期回款金额</td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td>正确/口径调整/数据不足</td><td></td></tr></tbody></table>`,49)])])}const u=a(n,[["render",i]]);export{b as __pageData,u as default};
